function solve(nums: number[], k: number): number {
    nums.sort((a, b) => a - b);
    const n = nums.length;
    let maxLen = 1; // At least one element is always balanced

    for (let i = 0; i < n; i++) {
        const target = k * nums[i];
        let low = i;
        let high = n - 1;
        let j = i - 1; // Initialize to invalid index

        while (low <= high) {
            const mid = Math.floor((low + high) / 2);
            if (nums[mid] <= target) {
                j = mid;
                low = mid + 1;
            } else {
                high = mid - 1;
            }
        }

        const currentLen = j - i + 1;
        if (currentLen > maxLen) {
            maxLen = currentLen;
        }
    }

    return n - maxLen;
}
